func storeObject(sha string, b []byte) {
	p := filepath.Join(objectsDir, sha[:2])
	os.MkdirAll(p, 0755)
	os.WriteFile(filepath.Join(p, sha[2:]), b, 0644)
}

func readObject(sha string) []byte {
	p := filepath.Join(objectsDir, sha[:2], sha[2:])
	b, _ := os.ReadFile(p)
	return b
}

func readIndex() map[string]string {
	m := make(map[string]string)
	f, err := os.Open(indexFile)
	if err != nil {
		return m
	}
	defer f.Close()
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		parts := strings.SplitN(sc.Text(), " ", 2)
		if len(parts) == 2 {
			m[parts[1]] = parts[0]
		}
	}
	return m
}

func writeIndex(m map[string]string) {
	var lines []string
	for f, sha := range m {
		lines = append(lines, sha+" "+f)
	}
	sort.Strings(lines)
	os.WriteFile(indexFile, []byte(strings.Join(lines, "\n")+"\n"), 0644)
}

func buildTree(idx map[string]string) map[string][]byte {
	tree := make(map[string][]byte)
	for f, sha := range idx {
		tree[f] = []byte(sha)
	}
	return tree
}

func writeTree(tree map[string][]byte) string {
	var names []string
	for n := range tree {
		names = append(names, n)
	}
	sort.Strings(names)
	var sb strings.Builder
	for _, n := range names {
		sb.WriteString(fmt.Sprintf("%s %s\n", n, sha1str(tree[n])))
	}
	s := sb.String()
	sha := sha1str([]byte(s))
	storeObject(sha, []byte(s))
	return sha
}

func readHead() string {
	b, _ := os.ReadFile(headFile)
	return strings.TrimSpace(string(b))
}

func updateHead(sha string) {
	os.WriteFile(headFile, []byte(sha+"\n"), 0644)
}

func writeConfig() error {
