}

func loadConfig() {
	b, _ := os.ReadFile(configFile)
	lines := strings.Split(string(b), "\n")
	for _, l := range lines {
		if strings.HasPrefix(l, "user.name ") {
			authorName = strings.TrimPrefix(l, "user.name ")
		}
		if strings.HasPrefix(l, "user.email ") {
			authorEmail = strings.TrimPrefix(l, "user.email ")
		}
	}
}
